mapper.sql:
WHERE r.deleted = 0

    AND r.customer_id = #{query.customerId}


    AND r.company_name LIKE CONCAT('%', #{query.companyName}, '%')


    AND r.receive_date >= #{query.receiveDateStart}


    AND r.receive_date <= #{query.receiveDateEnd}


    AND r.payer_name LIKE CONCAT('%', #{query.payerName}, '%')


    AND r.pay_method = #{query.payMethod}


    AND r.receiver_name LIKE CONCAT('%', #{query.receiverName}, '%')


    AND r.charge_end_date >= #{query.chargeEndDateStart}


    AND r.charge_end_date <= #{query.chargeEndDateEnd}


    AND r.amount >= #{query.amountMin}


    AND r.amount <= #{query.amountMax}


    AND DATE_FORMAT(r.receive_date, '%Y-%m') = DATE_FORMAT(CURDATE(), '%Y-%m')


    AND YEAR(r.receive_date) = YEAR(CURDATE())
